-- Modify "users" table
ALTER TABLE "public"."users" DROP COLUMN "sport", DROP COLUMN "college", ADD COLUMN "sport_id" uuid NULL, ADD COLUMN "college_id" uuid NULL, ADD CONSTRAINT "fk_users_college" FOREIGN KEY ("college_id") REFERENCES "public"."colleges" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, ADD CONSTRAINT "fk_users_sport" FOREIGN KEY ("sport_id") REFERENCES "public"."sports" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION;
-- Modify "posts" table
ALTER TABLE "public"."posts" ALTER COLUMN "author_id" TYPE uuid, ALTER COLUMN "sport_id" TYPE uuid, DROP COLUMN "likes", ALTER COLUMN "is_anonymous" SET DEFAULT false, ADD COLUMN "college_id" uuid NULL, ADD CONSTRAINT "fk_posts_author" FOREIGN KEY ("author_id") REFERENCES "public"."users" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, ADD CONSTRAINT "fk_posts_college" FOREIGN KEY ("college_id") REFERENCES "public"."colleges" ("id") ON UPDATE NO ACTION ON DELETE SET NULL, ADD CONSTRAINT "fk_posts_sport" FOREIGN KEY ("sport_id") REFERENCES "public"."sports" ("id") ON UPDATE NO ACTION ON DELETE SET NULL;
-- Modify "tag_posts" table
ALTER TABLE "public"."tag_posts" ADD CONSTRAINT "fk_tag_posts_post" FOREIGN KEY ("post_id") REFERENCES "public"."posts" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, ADD CONSTRAINT "fk_tag_posts_tag" FOREIGN KEY ("tag_id") REFERENCES "public"."tags" ("id") ON UPDATE NO ACTION ON DELETE CASCADE;
